const now = new Date();
const dayOfWeek = now.getDay();
let daysBack = 7;
if (dayOfWeek === 1) daysBack = 3;
else if (dayOfWeek === 5) daysBack = 4;
else if (dayOfWeek === 3) daysBack = 7;

const cutoffDate = new Date(now);
cutoffDate.setDate(cutoffDate.getDate() - daysBack);
cutoffDate.setHours(0, 0, 0, 0);

const results = [];

for (const item of $input.all()) {
  const d = item.json;

  // Cas 1 : Profil avec latestPosts (structure imbriquée)
  if (d.latestPosts && Array.isArray(d.latestPosts)) {
    for (const post of d.latestPosts) {
      const postDate = post.timestamp 
        ? new Date(post.timestamp) : null;
      if (!postDate || postDate < cutoffDate) continue;
      if (!post.shortCode) continue;

      let typeContenu = 'Photo';
      if (post.type === 'Video') typeContenu = 'Reel';
      if (post.type === 'Sidecar') typeContenu = 'Carrousel';

      results.push({
        json: {
          shortCode: post.shortCode,
          url_reel: post.type === 'Video' && post.productType === 'clips'
            ? `https://www.instagram.com/reel/${post.shortCode}/`
            : `https://www.instagram.com/p/${post.shortCode}/`,
          type_contenu: typeContenu,
          createur: d.username || post.ownerUsername || 'Inconnu',
          abonnes: d.followersCount || 0,
          vues: post.videoViewCount || post.videoPlayCount || 0,
          likes: post.likesCount || 0,
          commentaires: post.commentsCount || 0,
          description: post.caption || '',
          hashtags: (post.hashtags || []).join(', '),
          date_publication: postDate.toLocaleDateString('fr-FR'),
          video_url: post.videoUrl || '',
          musique: post.musicInfo
            ? `${post.musicInfo.artist_name || ''} - ${post.musicInfo.song_name || ''}`
            : 'Audio original',
          source: 'mots_cles_seo',
          mot_cle_source: d.inputUrl || ''
        }
      });
    }
    continue;
  }

  // Cas 2 : Post individuel (au cas où)
  if (!d.shortCode) continue;
  const postDate = d.timestamp ? new Date(d.timestamp) : null;
  if (!postDate || postDate < cutoffDate) continue;

  let typeContenu = 'Photo';
  if (d.type === 'Video') typeContenu = 'Reel';
  if (d.type === 'Sidecar') typeContenu = 'Carrousel';

  results.push({
    json: {
      shortCode: d.shortCode,
      url_reel: `https://www.instagram.com/p/${d.shortCode}/`,
      type_contenu: typeContenu,
      createur: d.ownerUsername || 'Inconnu',
      abonnes: 0,
      vues: d.videoPlayCount || d.videoViewCount || 0,
      likes: d.likesCount || 0,
      commentaires: d.commentsCount || 0,
      description: d.caption || '',
      hashtags: (d.hashtags || []).join(', '),
      date_publication: postDate.toLocaleDateString('fr-FR'),
      video_url: d.videoUrl || '',
      musique: d.musicInfo
        ? `${d.musicInfo.artist_name || ''} - ${d.musicInfo.song_name || ''}`
        : '',
