      mot_cle_source: d.inputUrl || ''
    }
  });
}

if (results.length === 0) {
  return [{ json: { vide: true } }];
}

return results;

for (const item of $input.all()) {
  // Ignorer les items vides
  if (item.json.vide) continue;

  const vues = item.json.vues || 0;
  const likes = item.json.likes || 0;
  const comments = item.json.commentaires || 0;
  const abonnes = item.json.abonnes || 0;

  // Viralité : si on a les abonnés, on calcule le ratio
  // Sinon on se base uniquement sur l'engagement
  let viralite = 0;
  if (abonnes > 0) {
    viralite = vues / abonnes;
  }

  // Engagement : adapté selon le type de contenu
  // Pour les Reels : basé sur les vues
  // Pour les carrousels/photos : basé sur les likes
  let engagement = 0;
  if (vues > 0) {
    engagement = ((likes + (comments * 3)) / vues) * 100;
  } else if (likes > 0) {
    engagement = comments * 3 / likes * 100;
  }

  // Score final adapté selon les données disponibles
  let score = 0;
  if (abonnes > 0) {
    score = (viralite * 0.6) + (engagement * 0.4);
  } else {
    // Sans abonnés, on pondère 100% engagement
    score = engagement;
  }

  item.json.score_viralite = parseFloat(viralite.toFixed(2));
  item.json.score_engagement = parseFloat(engagement.toFixed(2));
  item.json.score_final = parseFloat(score.toFixed(2));
  item.json.est_viral = viralite >= 5 ? "OUI" : abonnes === 0 ? "N/A" : "NON";
}

return $input.all().filter(i => !i.json.vide);

