const valid = [];
const rejected = [];

for (const item of $input.all()) {
  const d = item.json;

  // Ignorer les items vides
  if (d.vide) continue;

  // Vérifications
  const hasUrl = d.url_reel && d.url_reel.length > 10;
  const hasCreateur = d.createur && d.createur !== 'Inconnu';
  const hasEngagement = (d.vues > 0) || (d.likes > 0);
  const hasShortCode = d.shortCode && d.shortCode.length > 3;

  if (hasUrl && hasCreateur && hasEngagement && hasShortCode) {
    valid.push(item);
  } else {
    rejected.push({
      url: d.url_reel || 'N/A',
      raison: !hasUrl ? 'URL manquante' 
        : !hasCreateur ? 'Créateur inconnu'
        : !hasEngagement ? 'Aucune métrique'
        : 'ShortCode invalide'
    });
  }
}

// Log les rejets dans la console N8N
if (rejected.length > 0) {
  console.log(`[VALIDATION] ${rejected.length} items rejetés :`, 
    JSON.stringify(rejected));
}

// Si rien de valide, renvoyer un item marqueur
if (valid.length === 0) {
  return [{ json: { vide: true, raison: 'Aucun item valide après validation' } }];
}

return valid;

